_file_map = {

    "clients.baml": "// Learn more about clients at https://docs.boundaryml.com/docs/snippets/clients/overview\n\n// Using the new OpenAI Responses API for enhanced formatting\nclient<llm> CustomGPT5 {\n  provider openai-responses\n  options {\n    model \"gpt-5\"\n    api_key env.OPENAI_API_KEY\n  }\n}\n\nclient<llm> CustomGPT5Mini {\n  provider openai-responses\n  retry_policy Exponential\n  options {\n    model \"gpt-5-mini\"\n    api_key env.OPENAI_API_KEY\n  }\n}\n\n// Openai with chat completion\nclient<llm> CustomGPT5Chat {\n  provider openai\n  options {\n    model \"gpt-5\"\n    api_key env.OPENAI_API_KEY\n  }\n}\n\n// Latest Anthropic Claude 4 models\nclient<llm> CustomOpus4 {\n  provider anthropic\n  options {\n    model \"claude-opus-4-1-20250805\"\n    api_key env.ANTHROPIC_API_KEY\n  }\n}\n\nclient<llm> CustomSonnet4 {\n  provider anthropic\n  options {\n    model \"claude-sonnet-4-20250514\"\n    api_key env.ANTHROPIC_API_KEY\n  }\n}\n\nclient<llm> CustomHaiku {\n  provider anthropic\n  retry_policy Constant\n  options {\n    model \"claude-3-5-haiku-20241022\"\n    api_key env.ANTHROPIC_API_KEY\n  }\n}\n\n// Example Google AI client (uncomment to use)\n// client<llm> CustomGemini {\n//   provider google-ai\n//   options {\n//     model \"gemini-2.5-pro\"\n//     api_key env.GOOGLE_API_KEY\n//   }\n// }\n\n// Example AWS Bedrock client (uncomment to use)\n// client<llm> CustomBedrock {\n//   provider aws-bedrock\n//   options {\n//     model \"anthropic.claude-sonnet-4-20250514-v1:0\"\n//     region \"us-east-1\"\n//     // AWS credentials are auto-detected from env vars\n//   }\n// }\n\n// Example Azure OpenAI client (uncomment to use)\n// client<llm> CustomAzure {\n//   provider azure-openai\n//   options {\n//     model \"gpt-5\"\n//     api_key env.AZURE_OPENAI_API_KEY\n//     base_url \"https://MY_RESOURCE_NAME.openai.azure.com/openai/deployments/MY_DEPLOYMENT_ID\"\n//     api_version \"2024-10-01-preview\"\n//   }\n// }\n\n// Vertex AI client for Gemini models\nclient<llm> CustomGemini {\n  provider vertex-ai\n  options {\n    model \"gemini-2.0-flash-exp\"\n    location env.GCP_REGION\n    // Uses Google Cloud Application Default Credentials\n    // Set GCP_PROJECT_ID and GCP_REGION in your environment\n  }\n}\n\n// Vertex AI client for Anthropic models via Vertex\n// Notes: BAML may not have native vertex-anthropic provider\n// This uses openai-generic provider to connect to Vertex AI endpoint\nclient<llm> VertexSonnet4 {\n  provider openai-generic\n  options {\n    base_url env.VERTEX_ANTHROPIC_BASE_URL\n    model \"claude-sonnet-4-20250514\"\n    api_key env.VERTEX_ACCESS_TOKEN\n  }\n}\n\nclient<llm> VertexOpus4 {\n  provider openai-generic\n  options {\n    base_url env.VERTEX_ANTHROPIC_BASE_URL\n    model \"claude-opus-4-20250514\"\n    api_key env.VERTEX_ACCESS_TOKEN\n  }\n}\n\nclient<llm> VertexHaiku {\n  provider openai-generic\n  options {\n    base_url env.VERTEX_ANTHROPIC_BASE_URL\n    model \"claude-3-5-haiku-20241022\"\n    api_key env.VERTEX_ACCESS_TOKEN\n  }\n}\n\n// Example Ollama client for local models (uncomment to use)\n// client<llm> CustomOllama {\n//   provider openai-generic\n//   options {\n//     base_url \"http://localhost:11434/v1\"\n//     model \"llama4\"\n//     default_role \"user\" // Most local models prefer the user role\n//     // No API key needed for local Ollama\n//   }\n// }\n\n// https://docs.boundaryml.com/docs/snippets/clients/round-robin\nclient<llm> CustomFast {\n  provider round-robin\n  options {\n    // This will alternate between the two clients\n    strategy [CustomGPT5Mini, CustomHaiku]\n  }\n}\n\n// https://docs.boundaryml.com/docs/snippets/clients/fallback\nclient<llm> OpenaiFallback {\n  provider fallback\n  options {\n    // This will try the clients in order until one succeeds\n    strategy [CustomGPT5Mini, CustomGPT5]\n  }\n}\n\n// https://docs.boundaryml.com/docs/snippets/clients/retry\nretry_policy Constant {\n  max_retries 3\n  strategy {\n    type constant_delay\n    delay_ms 200\n  }\n}\n\nretry_policy Exponential {\n  max_retries 2\n  strategy {\n    type exponential_backoff\n    delay_ms 300\n    multiplier 1.5\n    max_delay_ms 10000\n  }\n}",
    "entity_resolution.baml": "// Entity Resolution: Semantic matching for knowledge graph deduplication\n// This file defines functions for identifying duplicate entities and edges using LLM-based matching\n\n// Represents a matched pair of entities\nclass EntityMatch {\n  entity1_id string @description(\"The unique identifier (name) of the first entity\")\n  entity2_id string @description(\"The unique identifier (name) of the second entity\")\n  is_duplicate bool @description(\"Whether these two entities represent the same real-world entity\")\n  confidence_level string @description(\"Confidence in the match decision: 'high', 'medium', or 'low'\")\n  reasoning string @description(\"Detailed explanation of why these entities are or aren't duplicates, considering name variations, types, descriptions, and attributes\")\n}\n\n// Represents a matched pair of edges (relationships)\nclass EdgeMatch {\n  edge1_id string @description(\"Identifier for first edge in format 'subject|predicate|object'\")\n  edge2_id string @description(\"Identifier for second edge in format 'subject|predicate|object'\")\n  is_duplicate bool @description(\"Whether these edges represent the same relationship\")\n  confidence_level string @description(\"Confidence in the match decision: 'high', 'medium', or 'low'\")\n  reasoning string @description(\"Detailed explanation considering subject/object similarity, predicate equivalence, and evidence overlap\")\n}\n\n// Simple entity representation for matching\nclass EntityForMatching {\n  id string @description(\"Entity unique identifier (name)\")\n  type string @description(\"Entity type from ontology\")\n  description string @description(\"Brief description of the entity\")\n  attributes string @description(\"JSON string of entity attributes\")\n}\n\n// Simple edge representation for matching\nclass EdgeForMatching {\n  id string @description(\"Edge identifier in format 'subject|predicate|object'\")\n  subject string @description(\"Subject entity name\")\n  predicate string @description(\"Relationship type\")\n  object string @description(\"Object entity name\")\n  evidence_summary string @description(\"Summary of supporting evidence\")\n}\n\n// Result of entity matching for a block\nclass EntityMatchingResult {\n  matches EntityMatch[] @description(\"List of identified duplicate pairs within this block\")\n  reasoning string @description(\"Overall reasoning about the matching process and decisions made\")\n}\n\n// Result of edge matching for a block\nclass EdgeMatchingResult {\n  matches EdgeMatch[] @description(\"List of identified duplicate edge pairs within this block\")\n  reasoning string @description(\"Overall reasoning about the matching process and decisions made\")\n}\n\n// Main function to match entities within a block\nfunction MatchEntities(\n  entities: EntityForMatching[],\n  context: string\n) -> EntityMatchingResult {\n  client CustomSonnet4\n  prompt #\"\n    You are an expert in entity resolution for knowledge graphs. Your task is to identify duplicate entities within a group of semantically similar entities.\n\n    {{ _.role(\"user\") }}\n    \n    **Context about this knowledge graph:**\n    {{ context if context else \"General domain knowledge graph\" }}\n\n    **Entities to analyze:**\n    {% for entity in entities %}\n    ---\n    ID: {{ entity.id }}\n    Type: {{ entity.type }}\n    Description: {{ entity.description }}\n    Attributes: {{ entity.attributes }}\n    {% endfor %}\n    ---\n\n    **Task:** \n    Identify which entities in this group are duplicates of each other. Consider:\n    \n    1. **Name variations**: \"TechCorp\", \"Tech Corp\", \"TechCorp Inc.\" likely refer to the same entity\n    2. **Semantic similarity**: \"NYC\" and \"New York City\" are the same\n    3. **Type consistency**: Entities must have compatible types to be duplicates\n    4. **Attribute alignment**: Similar or complementary attributes strengthen a match\n    5. **Description consistency**: Descriptions should be compatible, not contradictory\n    \n    **Guidelines:**\n    - Only mark entities as duplicates if you're confident they refer to the same real-world entity\n    - Use \"high\" confidence for clear matches (obvious name variations, identical descriptions)\n    - Use \"medium\" confidence for probable matches (semantic similarity, consistent attributes)\n    - Use \"low\" confidence for possible matches (weak signals, some inconsistency)\n    - Avoid false positives - when in doubt, mark is_duplicate as false\n    - Provide clear reasoning for each match decision\n    - Check for transitive consistency: if A matches B and B matches C, A should match C\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// Main function to match edges within a block\nfunction MatchEdges(\n  edges: EdgeForMatching[],\n  context: string\n) -> EdgeMatchingResult {\n  client CustomSonnet4\n  prompt #\"\n    You are an expert in entity resolution for knowledge graphs. Your task is to identify duplicate edges (relationships) within a group of semantically similar edges.\n\n    {{ _.role(\"user\") }}\n    \n    **Context about this knowledge graph:**\n    {{ context if context else \"General domain knowledge graph\" }}\n\n    **Edges to analyze:**\n    {% for edge in edges %}\n    ---\n    ID: {{ edge.id }}\n    Triple: {{ edge.subject }} -[{{ edge.predicate }}]-> {{ edge.object }}\n    Evidence: {{ edge.evidence_summary }}\n    {% endfor %}\n    ---\n\n    **Task:**\n    Identify which edges in this group are duplicates of each other. Consider:\n    \n    1. **Entity equivalence**: Subject and object entities should be the same or known duplicates\n    2. **Predicate equivalence**: Predicates should express the same relationship (e.g., \"works_at\" vs \"employed_by\")\n    3. **Evidence overlap**: Duplicates often cite the same or overlapping source text\n    4. **Direction consistency**: Ensure relationship direction is the same\n    5. **Temporal consistency**: Check if edges describe the same timeframe\n    \n    **Guidelines:**\n    - Only mark edges as duplicates if they represent the same relationship between the same entities\n    - Use \"high\" confidence for edges with identical subjects, predicates, objects\n    - Use \"medium\" confidence for edges with equivalent predicates and matching entities\n    - Use \"low\" confidence for edges with similar but not identical structure\n    - Edges with contradictory information (different dates, different evidence) are NOT duplicates\n    - Provide clear reasoning for each match decision\n    - Consider that edges from different sources can still be duplicates if they express the same fact\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n",
    "generators.baml": "// This helps use auto generate libraries you can use in the language of\n// your choice. You can have multiple generators if you use multiple languages.\n// Just ensure that the output_dir is different for each generator.\ngenerator target {\n    // Valid values: \"python/pydantic\", \"typescript\", \"ruby/sorbet\", \"rest/openapi\"\n    output_type \"python/pydantic\"\n\n    // Where the generated code will be saved (relative to baml_src/)\n    // BAML creates a baml_client/ subdir inside this path, so we use \"..\"\n    // to generate directly into spindle/baml_client/\n    output_dir \"..\"\n\n    // The version of the BAML package you have installed (e.g. same version as your baml-py or @boundaryml/baml).\n    // The BAML VSCode extension version should also match this version.\n    version \"0.214.0\"\n\n    // Valid values: \"sync\", \"async\"\n    // This controls what `b.FunctionName()` will be (sync or async).\n    default_client_mode sync\n}\n",
    "pipeline.baml": "// Ontology Pipeline: BAML definitions for semantic knowledge extraction\n// Implements the six-stage pipeline: Vocabulary, Metadata, Taxonomy, Thesaurus, Ontology, KG\n\n// =============================================================================\n// Stage 1: Controlled Vocabulary Types and Functions\n// =============================================================================\n\nclass VocabularyTerm {\n  term_id string @description(\"Unique identifier for this term\")\n  preferred_label string @description(\"The canonical/preferred form of this term\")\n  definition string @description(\"Clear definition explaining what this term means in context\")\n  synonyms string[] @description(\"Alternative terms or phrases that mean the same thing\")\n  domain string? @description(\"The subject domain this term belongs to (e.g., 'medical', 'legal', 'technology')\")\n}\n\nclass VocabularyExtractionResult {\n  terms VocabularyTerm[] @description(\"Extracted vocabulary terms with definitions\")\n  domain_summary string @description(\"Brief summary of the domains/topics covered in the text\")\n  reasoning string @description(\"Explanation of term selection and definition choices\")\n}\n\nfunction ExtractControlledVocabulary(\n  text: string,\n  existing_terms: VocabularyTerm[],\n  document_id: string\n) -> VocabularyExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are a knowledge organization expert specializing in controlled vocabulary development.\n    Your task is to extract key terms from the text and create clean, disambiguated vocabulary entries.\n\n    {{ _.role(\"user\") }}\n\n    TEXT TO ANALYZE:\n    {{ text }}\n\n    DOCUMENT ID: {{ document_id }}\n\n    {% if existing_terms|length > 0 %}\n    EXISTING VOCABULARY:\n    The following terms have already been extracted. You should:\n    1. Use consistent naming - if a term exists, use the SAME preferred_label\n    2. Add new synonyms to existing terms rather than creating duplicates\n    3. Only create new terms for genuinely different concepts\n    \n    {% for term in existing_terms %}\n    - {{ term.preferred_label }}: {{ term.definition }}\n      Synonyms: {{ term.synonyms | join(\", \") }}\n    {% endfor %}\n    {% endif %}\n\n    CONTROLLED VOCABULARY PRINCIPLES:\n\n    1. **Term Selection**: Identify key concepts, entities, and domain-specific terms\n       - Focus on nouns and noun phrases\n       - Include technical/domain terms that need definition\n       - Skip common words that don't need clarification\n\n    2. **Preferred Label**: Choose the most standard/canonical form\n       - Use singular form for countable nouns\n       - Use the most commonly accepted spelling\n       - Prefer full terms over abbreviations (but list abbreviations as synonyms)\n\n    3. **Definition**: Write clear, concise definitions\n       - Start with the category: \"A [category] that...\"\n       - Include distinguishing characteristics\n       - Keep to 1-2 sentences\n\n    4. **Synonyms**: List alternative forms\n       - Abbreviations and acronyms\n       - Variant spellings\n       - Related terms that are used interchangeably in this context\n\n    5. **Domain**: Identify the subject area\n       - Be specific but not overly narrow\n       - Examples: \"healthcare\", \"finance\", \"technology\", \"legal\"\n\n    DEDUPLICATION:\n    - If a concept already exists in the existing vocabulary, do NOT create a duplicate\n    - Instead, you may suggest additional synonyms in your reasoning\n    - Generate unique term_ids using format: \"term_[document_id]_[index]\"\n\n    {{ ctx.output_format }}\n  \"#\n}\n\nfunction ConsolidateVocabulary(\n  term_sets: VocabularyTerm[][]\n) -> VocabularyExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are a knowledge organization expert. Your task is to merge and deduplicate\n    vocabulary terms from multiple extraction runs into a single, coherent vocabulary.\n\n    {{ _.role(\"user\") }}\n\n    TERM SETS TO CONSOLIDATE:\n    {% for term_set in term_sets %}\n    --- Set {{ loop.index }} ---\n    {% for term in term_set %}\n    - {{ term.preferred_label }}: {{ term.definition }}\n      Synonyms: {{ term.synonyms | join(\", \") }}\n      Domain: {{ term.domain or \"unspecified\" }}\n    {% endfor %}\n    {% endfor %}\n\n    CONSOLIDATION RULES:\n\n    1. **Merge Duplicates**: Combine terms that refer to the same concept\n       - Keep the best/most complete definition\n       - Combine all synonyms from duplicate entries\n       - Use the most specific domain classification\n\n    2. **Resolve Conflicts**: When definitions differ slightly\n       - Prefer more precise definitions\n       - Incorporate unique aspects from each\n       - Note any genuine ambiguity\n\n    3. **Maintain Consistency**: Ensure the final vocabulary is coherent\n       - No duplicate preferred_labels\n       - Synonyms should point to only one preferred term\n       - Domains should be consistently applied\n\n    4. **Generate New IDs**: Create new term_ids using format: \"term_consolidated_[index]\"\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// =============================================================================\n// Stage 2: Metadata Standards Types and Functions\n// =============================================================================\n\nclass MetadataElement {\n  element_id string @description(\"Unique identifier for this metadata element\")\n  name string @description(\"Name of the metadata field (e.g., 'author', 'publication_date')\")\n  element_type string @description(\"Type: 'structural', 'descriptive', or 'administrative'\")\n  description string @description(\"What this metadata element captures\")\n  data_type string @description(\"Expected data type: 'string', 'int', 'float', 'bool', 'date', 'list'\")\n  required bool @description(\"Whether this element is required for all documents\")\n  examples string[] @description(\"Example values this element might contain\")\n}\n\nclass MetadataExtractionResult {\n  elements MetadataElement[] @description(\"Discovered metadata schema elements\")\n  reasoning string @description(\"Explanation of the metadata schema design\")\n}\n\nfunction ExtractMetadataSchema(\n  text: string,\n  document_metadata: string,\n  existing_elements: MetadataElement[]\n) -> MetadataExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are an information architect specializing in metadata standards.\n    Analyze the document to identify metadata elements that describe its structure and content.\n\n    {{ _.role(\"user\") }}\n\n    DOCUMENT TEXT (sample):\n    {{ text }}\n\n    DOCUMENT METADATA (if available):\n    {{ document_metadata }}\n\n    {% if existing_elements|length > 0 %}\n    EXISTING METADATA SCHEMA:\n    {% for elem in existing_elements %}\n    - {{ elem.name }} ({{ elem.element_type }}): {{ elem.description }}\n    {% endfor %}\n    {% endif %}\n\n    METADATA ELEMENT TYPES:\n\n    1. **Structural Metadata** - For machine readability\n       - Format, encoding, file type\n       - Structure markers (sections, chapters)\n       - Technical specifications\n\n    2. **Descriptive Metadata** - For context and discovery\n       - Title, author, subject\n       - Keywords, abstract, summary\n       - Topic classification\n\n    3. **Administrative Metadata** - For maintenance and lineage\n       - Creation date, modification date\n       - Source, provenance\n       - Rights, access restrictions\n       - Version information\n\n    GUIDELINES:\n    - Identify patterns in the document that suggest metadata fields\n    - Consider what metadata would be useful for search and organization\n    - Be specific about data types and whether fields are required\n    - Generate unique element_ids using format: \"meta_[index]\"\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// =============================================================================\n// Stage 3: Taxonomy Types and Functions\n// =============================================================================\n\nclass TaxonomyRelation {\n  parent_term string @description(\"The broader/parent concept label\")\n  child_term string @description(\"The narrower/child concept label\")\n  relation_type string @description(\"Relationship type: 'broader' or 'narrower'\")\n  confidence string @description(\"Confidence level: 'high', 'medium', or 'low'\")\n}\n\nclass TaxonomyExtractionResult {\n  relations TaxonomyRelation[] @description(\"Hierarchical relationships between terms\")\n  root_terms string[] @description(\"Top-level terms with no parents\")\n  reasoning string @description(\"Explanation of the taxonomic structure\")\n}\n\nfunction ExtractTaxonomy(\n  terms: VocabularyTerm[],\n  text: string,\n  existing_relations: TaxonomyRelation[]\n) -> TaxonomyExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are a taxonomist expert in hierarchical classification systems.\n    Build a taxonomy by identifying parent-child relationships between vocabulary terms.\n\n    {{ _.role(\"user\") }}\n\n    VOCABULARY TERMS:\n    {% for term in terms %}\n    - {{ term.preferred_label }}: {{ term.definition }}\n      Domain: {{ term.domain or \"unspecified\" }}\n    {% endfor %}\n\n    CONTEXT TEXT:\n    {{ text }}\n\n    {% if existing_relations|length > 0 %}\n    EXISTING TAXONOMY RELATIONS:\n    {% for rel in existing_relations %}\n    - {{ rel.parent_term }} > {{ rel.child_term }}\n    {% endfor %}\n    {% endif %}\n\n    TAXONOMY PRINCIPLES:\n\n    1. **Hierarchical Structure**\n       - Each term can have only ONE parent (strict hierarchy)\n       - Terms without parents become root terms\n       - Deeper levels = more specific concepts\n\n    2. **IS-A Relationships**\n       - Child \"is a type of\" parent\n       - Example: \"Dog\" is-a \"Animal\"\n       - Avoid part-of relationships (those go in thesaurus)\n\n    3. **Consistency**\n       - Siblings should be at the same level of abstraction\n       - Use the vocabulary's preferred_label exactly\n       - Don't create relations for terms not in the vocabulary\n\n    4. **Confidence Levels**\n       - high: Clear hierarchical relationship from text/domain knowledge\n       - medium: Reasonable inference but not explicitly stated\n       - low: Plausible but uncertain\n\n    Identify root terms (concepts with no broader parent in this vocabulary).\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// =============================================================================\n// Stage 4: Thesaurus Types and Functions\n// =============================================================================\n\nclass ThesaurusEntry {\n  entry_id string @description(\"Unique identifier for this entry\")\n  term_id string @description(\"Reference to the vocabulary term\")\n  preferred_label string @description(\"The preferred term label\")\n  use_for string[] @description(\"Non-preferred synonyms (USE_FOR/UF relationships)\")\n  broader_terms string[] @description(\"Broader/parent terms (BT relationships)\")\n  narrower_terms string[] @description(\"Narrower/child terms (NT relationships)\")\n  related_terms string[] @description(\"Associated terms (RT relationships)\")\n  scope_note string? @description(\"Definition or scope clarification (SN)\")\n}\n\nclass ThesaurusExtractionResult {\n  entries ThesaurusEntry[] @description(\"Thesaurus entries with semantic relationships\")\n  reasoning string @description(\"Explanation of relationship assignments\")\n}\n\nfunction ExtractThesaurus(\n  terms: VocabularyTerm[],\n  taxonomy_relations: TaxonomyRelation[],\n  text: string\n) -> ThesaurusExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are a thesaurus construction expert following ISO 25964 standards.\n    Build thesaurus entries by adding semantic relationships to vocabulary terms.\n\n    {{ _.role(\"user\") }}\n\n    VOCABULARY TERMS:\n    {% for term in terms %}\n    - {{ term.preferred_label }}: {{ term.definition }}\n      Synonyms: {{ term.synonyms | join(\", \") }}\n    {% endfor %}\n\n    EXISTING TAXONOMY (BT/NT relationships):\n    {% for rel in taxonomy_relations %}\n    - {{ rel.parent_term }} BT {{ rel.child_term }}\n    {% endfor %}\n\n    CONTEXT TEXT:\n    {{ text }}\n\n    THESAURUS RELATIONSHIP TYPES (ISO 25964):\n\n    1. **USE / USE_FOR (UF)**: Synonym control\n       - Preferred term USE non-preferred\n       - Non-preferred term USE_FOR preferred\n       - From vocabulary synonyms\n\n    2. **Broader Term (BT)**: Hierarchical - genus\n       - From taxonomy parent relationships\n       - \"Concept A is a type of Concept B\"\n\n    3. **Narrower Term (NT)**: Hierarchical - species\n       - From taxonomy child relationships\n       - Inverse of BT\n\n    4. **Related Term (RT)**: Associative\n       - NOT hierarchical (no is-a relationship)\n       - Concepts often discussed together\n       - Same domain, complementary concepts\n       - Avoid if BT/NT already connects them\n\n    5. **Scope Note (SN)**: Definition/clarification\n       - From vocabulary definition\n       - Additional context if needed\n\n    GUIDELINES:\n    - BT/NT come from taxonomy_relations\n    - UF comes from vocabulary synonyms  \n    - RT is for non-hierarchical associations found in text\n    - Generate entry_ids using format: \"thes_[index]\"\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// =============================================================================\n// Stage 5: Ontology Enhancement (uses existing RecommendOntology but with context)\n// =============================================================================\n\nclass OntologyEnhancementResult {\n  entity_types EntityType[] @description(\"Recommended entity types informed by vocabulary\")\n  relation_types RelationType[] @description(\"Recommended relation types informed by thesaurus\")\n  reasoning string @description(\"How vocabulary/taxonomy informed the ontology design\")\n}\n\nfunction EnhanceOntologyFromPipeline(\n  text: string,\n  vocabulary: VocabularyTerm[],\n  thesaurus_entries: ThesaurusEntry[],\n  scope: string\n) -> OntologyEnhancementResult {\n  client CustomFast\n  prompt #\"\n    You are an ontology engineer. Design an ontology for knowledge graph extraction,\n    informed by the controlled vocabulary and thesaurus already built for this corpus.\n\n    {{ _.role(\"user\") }}\n\n    CONTROLLED VOCABULARY:\n    {% for term in vocabulary %}\n    - {{ term.preferred_label }}: {{ term.definition }}\n      Domain: {{ term.domain or \"general\" }}\n    {% endfor %}\n\n    THESAURUS RELATIONSHIPS:\n    {% for entry in thesaurus_entries %}\n    - {{ entry.preferred_label }}\n      {% if entry.broader_terms|length > 0 %}BT: {{ entry.broader_terms | join(\", \") }}{% endif %}\n      {% if entry.related_terms|length > 0 %}RT: {{ entry.related_terms | join(\", \") }}{% endif %}\n    {% endfor %}\n\n    SAMPLE TEXT:\n    {{ text }}\n\n    SCOPE: {{ scope }}\n\n    ONTOLOGY DESIGN PRINCIPLES:\n\n    1. **Entity Types from Vocabulary**\n       - High-level vocabulary terms often become entity types\n       - Root taxonomy terms are good candidates\n       - Group related terms under entity types\n\n    2. **Relation Types from Thesaurus**\n       - RT (related term) relationships suggest relation types\n       - Consider the semantic nature of associations\n       - Ensure domain/range constraints match entity types\n\n    3. **Scope Guidelines**\n       {% if scope == \"minimal\" %}\n       - Essential types only (3-8 entities, 4-10 relations)\n       - Broad categories, minimal attributes\n       {% elif scope == \"balanced\" %}\n       - Core types plus important distinctions (6-12 entities, 8-15 relations)\n       - Standard attributes for each type\n       {% else %}\n       - Comprehensive coverage (10-20 entities, 12-25 relations)\n       - Detailed attributes and nuanced relations\n       {% endif %}\n\n    4. **Attribute Design**\n       - Use vocabulary terms to inform attributes\n       - Consider what properties distinguish entities\n\n    {{ ctx.output_format }}\n  \"#\n}\n\n// =============================================================================\n// Utility: Import EntityType and RelationType from spindle.baml\n// =============================================================================\n\n// Note: EntityType and RelationType are already defined in spindle.baml\n// They are automatically available in the BAML client\n\n",
    "spindle.baml": "// Spindle: Knowledge Graph Triple Extraction\n// This file defines the data structures and extraction function for building knowledge graphs from text\n\n// Source metadata for tracking where a triple came from\nclass SourceMetadata {\n  source_name string @description(\"The name or identifier of the source document\")\n  source_url string? @description(\"Optional URL of the source document\")\n}\n\n// Character span indicating text evidence for a triple\nclass CharacterSpan {\n  text string @description(\"The exact text from the source that supports this triple\")\n  start int? @description(\"Starting character index in the source text (0-based, computed in post-processing)\")\n  end int? @description(\"Ending character index in the source text (exclusive, computed in post-processing)\")\n}\n\n// Attribute definition for entity types in the ontology\nclass AttributeDefinition {\n  name string @description(\"The name of the attribute (e.g., 'campaign_launch_dt', 'founded_date')\")\n  type string @description(\"Data type: 'string', 'int', 'float', 'bool', 'date', or a nested object schema definition\")\n  description string @description(\"A description of what this attribute represents\")\n}\n\n// Attribute value in extracted entities (includes type metadata)\nclass AttributeValue {\n  value string? @description(\"The extracted value as a string, or null if not found in the text\")\n  type string @description(\"The data type of this attribute (matches the type from AttributeDefinition)\")\n}\n\n// Structured entity in a triple\nclass Entity {\n  name string @description(\"The entity's name or identifier extracted from the text\")\n  type string @description(\"The entity type from the ontology (must match an EntityType.name exactly)\")\n  description string @description(\"A brief description of the entity generated from the text context\")\n  custom_atts map<string, AttributeValue> @description(\"Type-specific attributes as defined in the entity type's AttributeDefinition list\")\n}\n\n// A triple represents a subject-predicate-object relationship with supporting evidence\nclass Triple {\n  subject Entity @description(\"The subject entity with full metadata and attributes\")\n  predicate string @description(\"The relationship/predicate connecting subject and object\")\n  object Entity @description(\"The object entity with full metadata and attributes\")\n  source SourceMetadata @description(\"Metadata about the source of this triple\")\n  supporting_spans CharacterSpan[] @description(\"Character spans in the source text that support this triple\")\n  extraction_datetime string? @description(\"ISO 8601 datetime when this triple was extracted (set automatically in post-processing)\")\n}\n\n// Defines a type of entity that can appear in the knowledge graph\nclass EntityType {\n  name string @description(\"The name of the entity type (e.g., 'Person', 'Organization', 'Campaign')\")\n  description string @description(\"A description of what this entity type represents\")\n  attributes AttributeDefinition[] @description(\"List of custom attributes that should be extracted for entities of this type\")\n}\n\n// Defines a type of relationship between entities\nclass RelationType {\n  name string @description(\"The name of the relation type (e.g., 'works_at', 'located_in')\")\n  description string @description(\"A description of what this relation represents\")\n  domain string @description(\"The entity type that can be the subject of this relation\")\n  range string @description(\"The entity type that can be the object of this relation\")\n}\n\n// An ontology defines the structure of the knowledge graph\nclass Ontology {\n  entity_types EntityType[] @description(\"List of valid entity types\")\n  relation_types RelationType[] @description(\"List of valid relation types\")\n}\n\n// The result of triple extraction\nclass ExtractionResult {\n  triples Triple[] @description(\"List of extracted triples from the text\")\n  reasoning string @description(\"Explanation of the extraction decisions and entity consistency choices\")\n}\n\n// Main function to extract knowledge graph triples from text\nfunction ExtractTriples(\n  text: string,\n  ontology: Ontology,\n  source_metadata: SourceMetadata,\n  existing_triples: Triple[]\n) -> ExtractionResult {\n  client CustomFast\n  prompt #\"\n    You are a knowledge graph extraction expert. Your task is to extract structured triples (subject-predicate-object) from the provided text, with rich entity metadata, custom attributes, and supporting evidence.\n\n    {{ _.role(\"user\") }}\n    \n    ONTOLOGY:\n    You must extract triples that conform to the following ontology:\n    \n    Valid Entity Types:\n    {% for entity_type in ontology.entity_types %}\n    - {{ entity_type.name }}: {{ entity_type.description }}\n      {% if entity_type.attributes|length > 0 %}\n      Custom Attributes:\n      {% for attr in entity_type.attributes %}\n        * {{ attr.name }} ({{ attr.type }}): {{ attr.description }}\n      {% endfor %}\n      {% endif %}\n    {% endfor %}\n    \n    Valid Relation Types:\n    {% for relation_type in ontology.relation_types %}\n    - {{ relation_type.name }}: {{ relation_type.description }}\n      (Domain: {{ relation_type.domain }}, Range: {{ relation_type.range }})\n    {% endfor %}\n    \n    SOURCE METADATA:\n    Source Name: {{ source_metadata.source_name }}\n    {% if source_metadata.source_url %}\n    Source URL: {{ source_metadata.source_url }}\n    {% endif %}\n    \n    EXISTING TRIPLES:\n    {% if existing_triples|length > 0 %}\n    The following triples have already been extracted from OTHER sources. You MUST:\n    1. Use consistent entity names - if an entity appears in existing triples, use the EXACT same name\n    2. Maintain entity identity - recognize when entities in the new text are the same as entities in existing triples\n    3. Duplicate triples ARE ALLOWED if they come from different sources (different source names)\n    4. If you extract the same fact that exists in existing triples, it's okay as long as it's from this new source\n    \n    {% for triple in existing_triples %}\n    - {{ triple.subject.name }} ({{ triple.subject.type }}) -> {{ triple.predicate }} -> {{ triple.object.name }} ({{ triple.object.type }}) [from: {{ triple.source.source_name }}]\n    {% endfor %}\n    {% else %}\n    This is the first extraction, so there are no existing triples to consider.\n    {% endif %}\n    \n    TEXT TO ANALYZE:\n    {{ text }}\n    \n    ENTITY EXTRACTION INSTRUCTIONS:\n    \n    For each entity in a triple (both subject and object), you MUST provide:\n    \n    1. **name**: The entity's name or identifier from the text\n       - Use clear, consistent names (e.g., \"John Smith\" not \"John\" or \"Smith\")\n       - If the entity appears in existing triples, use the EXACT same name\n    \n    2. **type**: The entity type from the ontology\n       - Must match exactly one of the EntityType names defined above\n       - Check domain/range constraints in relation types\n    \n    3. **description**: A brief description of the entity\n       - Generate this from the text context (1-2 sentences)\n       - Include relevant details that help identify or characterize the entity\n       - Be concise but informative\n    \n    4. **custom_atts**: Extract ALL attributes defined for this entity type\n       - Format: {\"attribute_name\": {\"value\": \"extracted_value\", \"type\": \"attribute_type\"}}\n       - Set \"value\" to null if the attribute is not mentioned in the text\n       - \"type\" must match the type from the AttributeDefinition\n       - Extract dates in ISO format (YYYY-MM-DD) when possible\n       - For nested objects, use JSON string representation\n    \n    TRIPLE EXTRACTION INSTRUCTIONS:\n    \n    1. Extract all meaningful triples from the text that conform to the ontology\n    2. Only use entity types and relation types defined in the ontology\n    3. For each triple, identify TEXT SPANS that provide evidence:\n       - Copy the EXACT text from the source that supports the triple\n       - You can include multiple text spans if evidence is spread across different parts\n       - Be precise - copy text exactly as it appears, including punctuation and spacing\n       - Include enough context to make the evidence clear\n    4. Provide reasoning explaining your extraction decisions\n    \n    EXAMPLE:\n    \n    Text: \"The Check Your A1C campaign launched on August 10, 2025, targeting diabetic members to remind them to get their A1C checked.\"\n    \n    Ontology has EntityType \"Campaign\" with attributes:\n    - campaign_launch_dt (date): Launch date\n    - campaign_completion_dt (date): Completion date\n    \n    Extracted entity for subject:\n    {\n      \"name\": \"Check Your A1C campaign\",\n      \"type\": \"Campaign\",\n      \"description\": \"A campaign targeting diabetic members to remind them to get their A1C checked\",\n      \"custom_atts\": {\n        \"campaign_launch_dt\": {\"value\": \"2025-08-10\", \"type\": \"date\"},\n        \"campaign_completion_dt\": {\"value\": null, \"type\": \"date\"}\n      }\n    }\n    \n    Note: Character indices for supporting spans will be computed automatically in post-processing.\n    \n    {{ ctx.output_format }}\n  \"#\n}\n\n\n",
}

def get_baml_files():
    return _file_map